1	/**
2	 * Onboarding state shape and the discriminated union of actions the reducer
3	 * accepts. The reducer is the single mutation point; every effect/component
4	 * dispatches into it. Keep this file authoritative for what the flow
5	 * remembers and how it can change.
6	 */
7	
8	import type { ClarifyAnswer, ClarifyQuestion } from "../types";
9	import type {
10	  OnboardingStage,
11	  PersonalizationData,
12	  StagePayloads,
13	} from "../types/websocket";
14	
15	/**
16	 * Linear stage queue rendered by the page. Each stage advances forward only,
17	 * driven by either a user action (ack / confirm) or a backend "no data, skip"
18	 * signal. `getStage` walks the queue once per render — components should
19	 * never compute this themselves.
20	 */
21	export type Stage =
22	  | "questions"
23	  | "focus"
24	  | "clarify"
25	  | "processing"
26	  | "revealWriting"
27	  | "revealTodos"
28	  | "workflows"
29	  | "platforms"
30	  | "chat";
31	
32	export interface OnboardingState {
33	  /** Answered Q&A keyed by FIELD_NAMES (name, profession, gmail, focus). */
34	  responses: Record<string, string>;
35	  /** Index into `questions[]`; equals questions.length once Q&A is finished. */
36	  questionIndex: number;
37	  /** In-flight text input value for the active text question. */
38	  draftText: string;
39	  /** In-flight Autocomplete value for the profession question. */
40	  draftProfession: string | null;
41	
42	  /** Latest server-side personalization snapshot (REST + WS-merged). */
43	  server: PersonalizationData | null;
44	
45	  /**
46	   * Live status text from the backend, scoped per stage so a late
47	   * progress event from one stage cannot bleed into the visible label of
48	   * another. Keyed by the emitting `OnboardingStage`.
49	   */
50	  progressByStage: Partial<Record<OnboardingStage, string>>;
51	  /** Set of pipeline stages that have emitted a completion event. */
52	  completedStages: Set<OnboardingStage>;
53	
54	  /** User confirmed the writing-style reveal card. */
55	  ackedWritingStyle: boolean;
56	  /** User confirmed (or skipped) the todos reveal card. */
57	  ackedTodos: boolean;
58	
59	  /** User clicked "Understood" on the workflows reveal card. */
60	  workflowsConfirmed: boolean;
61	  /** User finished the platform-connect step — either connected or skipped. */
62	  platformsConfirmed: boolean;
63	  /** Messaging platform the user linked during the platforms stage, if any. */
64	  connectedPlatform: string | null;
65	
66	  /** Pending todo to auto-send into the chat conversation once it's ready. */
67	  todoExecutionMessage: string | null;
68	  /**
69	   * Throwaway conversation id the run-now demo streams into. Generated fresh
70	   * on every Run-Now click so the demo never bleeds into the welcome
71	   * conversation (which the user lands in after "Continue to GAIA").
72	   */
73	  todoExecutionConvoId: string | null;
74	  /**
75	   * User clicked Run on a todo. The `revealTodos` stage swaps its todo grid
76	   * for the chat stream in-place; the stage stays active until the user
77	   * dispatches `ackTodoDemo` from the post-demo Continue button.
78	   */
79	  todoExecutionStarted: boolean;
80	  /**
81	   * The todo the user clicked Run on. Surfaced as a static "selected todo"
82	   * indicator at the top of the demo container — the raw auto-sent user
83	   * message itself is hidden from the stream.
84	   */
85	  todoExecutionTodo: {
86	    id: string;
87	    title: string;
88	    sourceEmail: { sender: string; subject: string } | null;
89	  } | null;
90	
91	  /** Restart in progress — UI is locked while the server `/reset` runs. */
92	  isRestarting: boolean;
93	
94	  /**
95	   * No-Gmail clarify stage. The 3 LLM-generated follow-up questions asked
96	   * after the focus answer so the todo generator has scope/blocker/constraint
97	   * signal. `null` means we haven't fetched them yet; an empty array would
98	   * mean the backend declined to ask any.
99	   */
100	  clarifyQuestions: ClarifyQuestion[] | null;
101	  /** Per-question answer, keyed by question id. Missing key = not yet answered. */
102	  clarifyAnswers: Record<string, ClarifyAnswer>;
103	  /** Active tab in the clarify composer; defaults to the first question id. */
104	  clarifyActiveTab: string | null;
105	  /** In-flight custom text inputs per question id (reveals when "Other" is chosen). */
106	  clarifyCustomDrafts: Record<string, string>;
107	  clarifyOtherSelected: Record<string, boolean>;
108	  /** True once the user clicks "Submit & continue" on the clarify composer. */
109	  clarifySubmitted: boolean;
110	}
111	
112	export type Action =
113	  /** Live-update the active text question's draft input. */
114	  | { type: "draftText"; value: string }
115	  /** Live-update the profession Autocomplete draft. */
116	  | { type: "draftProfession"; value: string | null }
117	  /** User submitted an answer; advances `questionIndex`. */
118	  | { type: "answer"; field: string; value: string }
119	  /** Full personalization snapshot from REST (poll or initial fetch). */
120	  | { type: "serverSnapshot"; data: PersonalizationData }
121	  /** Partial patch from a WS stage event. */
122	  | {
123	      type: "serverPatch";
124	      patch: Partial<PersonalizationData>;
125	    }
126	  /**
127	   * Live status string emitted by a specific backend stage. Stored under
128	   * the stage that emitted it so the UI can scope display per step.
129	   */
130	  | { type: "progress"; stage: OnboardingStage; message: string }
131	  /** A backend stage finished — used to drive the processing checklist. */
132	  | { type: "stageComplete"; stage: OnboardingStage }
133	  /** User confirmed the writing-style reveal card. */
134	  | { type: "ackWriting" }
135	  /** User confirmed (or skipped) the todos reveal card. */
136	  | { type: "ackTodos" }
137	  /** User clicked "Understood" on the workflows reveal card. */
138	  | { type: "confirmWorkflows" }
139	  /** User finished the platform-connect popup flow. */
140	  | { type: "platformConnected"; platform: string }
141	  /** User skipped the platform-connect step without picking a platform. */
142	  | { type: "skipPlatforms" }
143	  /** User clicked Run on a todo; queues the message + flips the in-place
144	   *  chat stream on inside the `revealTodos` stage. Does NOT advance the
145	   *  stage — `ackTodoDemo` does that after the demo finishes. */
146	  | {
147	      type: "executeTodo";
148	      message: string;
149	      convoId: string;
150	      todo: {
151	        id: string;
152	        title: string;
153	        sourceEmail: { sender: string; subject: string } | null;
154	      };
155	    }
156	  /** Chat stage consumed the pending todo execution message. */
157	  | { type: "clearTodoExecutionMessage" }
158	  /** User clicked Continue after the in-place todo demo finished streaming;
159	   *  advances the cursor past `revealTodos` into `workflows`. */
160	  | { type: "ackTodoDemo" }
161	  /** Restart kicked off — flips state back to initial and locks UI. */
162	  | { type: "restartStart" }
