// ── Progress bar (fixed) ──────────────────────────────────────────────────────

// `OnboardingProgress` uses `position: fixed top-0`. Wrapping it in a parent
// with a `transform` establishes a new containing block so the fixed bar is
// scoped to the demo card instead of pinned to the viewport.
function ProgressDemo() {
  const [step, setStep] = useState(2);
  const total = 7;
  return (
    <DemoSection label="OnboardingProgress (top bar + restart)">
      <div
        className="relative h-20 overflow-hidden rounded-2xl border border-zinc-800 bg-primary-bg"
        style={{ transform: "translateZ(0)" }}
      >
        <OnboardingProgress
          currentStep={step}
          totalSteps={total}
          onRestart={() => setStep(0)}
        />
      </div>
      <div className="mt-2 flex items-center gap-2">
        <button
          type="button"
          onClick={() => setStep((s) => Math.max(0, s - 1))}
          className="cursor-pointer rounded-lg bg-zinc-800 px-3 py-1.5 text-xs text-zinc-400 hover:bg-zinc-700"
        >
          ← Step
        </button>
        <span className="text-xs text-zinc-500">
          {step} / {total}
        </span>
        <button
          type="button"
          onClick={() => setStep((s) => Math.min(total, s + 1))}
          className="cursor-pointer rounded-lg bg-zinc-700 px-3 py-1.5 text-xs text-zinc-200 hover:bg-zinc-600"
        >
          Step →
        </button>
      </div>
    </DemoSection>
  );
}

